<?php declare(strict_types=1); namespace App\Http\Controllers\Btaq; use App\Http\Controllers\Controller; use App\Models\BtaqProgram; use Illuminate\Http\Request; final class BtaqProgramController extends Controller{public function index(){return view('btaq.programs.index',['programs'=>BtaqProgram::query()->orderBy('sort_order')->paginate(15)]);} public function create(){return view('btaq.programs.form',['program'=>new BtaqProgram]);} public function store(Request $r){$d=$this->data($r);$p=BtaqProgram::create($d);activity('btaq')->performedOn($p)->event('btaq.program.created')->log('Program BTAQ dibuat');return redirect()->route('btaq-programs.show',$p)->with('status','Program BTAQ disimpan.');} public function show(BtaqProgram $btaqProgram){return view('btaq.programs.show',['program'=>$btaqProgram]);} public function edit(BtaqProgram $btaqProgram){return view('btaq.programs.form',['program'=>$btaqProgram]);} public function update(Request $r,BtaqProgram $btaqProgram){$btaqProgram->update($this->data($r));activity('btaq')->performedOn($btaqProgram)->event('btaq.program.updated')->log('Program BTAQ diperbarui');return redirect()->route('btaq-programs.show',$btaqProgram)->with('status','Program BTAQ diperbarui.');} public function toggle(BtaqProgram $btaqProgram){$btaqProgram->update(['is_active'=>!$btaqProgram->is_active]);return back()->with('status','Status program diperbarui.');} private function data(Request $r):array{return $r->validate(['name'=>'required|string|max:150','code'=>'required|string|max:50','description'=>'nullable|string','sort_order'=>'nullable|integer','is_active'=>'nullable|boolean','uses_reading_progress'=>'nullable|boolean','uses_memorization_progress'=>'nullable|boolean','uses_tajwid_assessment'=>'nullable|boolean','uses_makhraj_assessment'=>'nullable|boolean','notes'=>'nullable|string']);}}
